杭电多校 2 补题 1010 女神的睿智 按顺序合并 8 块碎片，如果两片相同，合成后仍相同，如不同，取左侧的，最后合成大碎片时，如果两片相同，不变，如果不同，取出现次数最多的，如果不确定，输出N。
签到，直接暴力
#include &lt;bits/stdc++.h&gt; using namespace std; void solve(){ string t,s; cin&gt;&gt;s; map&lt;char,int&gt;vis; for(int i=0;i&lt;8;i++){ if(i%2!=1)t+=s[i]; vis[s[i]]++; } s=t; t=&#34;&#34;; for(int i=0;i&lt;4;i++){ if(i%2!=1)t+=s[i]; } if(vis[t[0]]==vis[t[1]])cout&lt;&lt;&#34;N&#34;; else if(vis[t[0]]&gt;vit[t[1]])cout&lt;&lt;t[0]; else cout&lt;&lt;t[1]; cout&lt;&lt;&#34;\n&#34;; } int main(){ int t=1; cin&gt;&gt;t; while(t--)solve(); return 0; } 1007 URL 划分 输入: 1 s3://hdu-oj-bucket/problem=1/type=data/ 输出： s3 hdu-oj-bucket problem=1 type=data
签到，按题意拆分字符串即可
#include &lt;bits/stdc++.h&gt; using namespace std; void solve(){ string s; cin&gt;&gt;s; int pos = s.find(&#34;://&#34;); cout&lt;&lt;s.substr(0,pos)&lt;&lt;&#34;\n&#34;; pos+=3; int now = s.find(&#34;/&#34;,pos); cout&lt;&lt;s.substr(pos,now-pos)&lt;&lt;&#34;\n&#34;; while(1){ pos=now+1; if(pos&gt;=s.size())break; now = s.find(&#34;/&#34;,pos); string t = s.substr(pos,now-pos); int flag = t.find(&#34;=&#34;); if(flag!=-1)cout&lt;&lt;t&lt;&lt;&#34;\n&#34;; } } int main(){ int t=1; cin&gt;&gt;t; while(t--)solve(); return 0; } 鸡爪 给 n 条边，任意顶点，构造数量最多的鸡爪，同时保证输出每条边的两个顶点时，保证行优先遍历，字典序最小。
鸡爪的定义：1 个顶点，和它所连的 3 条边，不包括其他顶点，不可重复利用。
构造，易想出 n 条边，最多构造出 n/3 个鸡爪，多出的 1 或 2 个边，补到顶点1上即可。
因为字典序最小，所以顶点 1 上连的边肯定最多，我们就让 1 连到所有的顶点上，这样其他所有构造鸡爪的顶点 n 都能用上 1-n 这条边。因此 1 自己用的边肯定是入度最小的几个顶点，即编号最大的顶点，类推到之后的顶点，都是先采用与其之前的顶点的边，再从最后面选。到顶点 4 开始，不再需要往后采用，因为前面有 3 个顶点提供边，不再需要额外的顶点来提供边。
#include &lt;bits/stdc++.h&gt; using namespace std; void solve(){ int n; cin&gt;&gt;n; if(n&gt;=3){ int now=0,cnt=n/3+3; for(int i=1;i&lt;=min(n/3,3);i++){ for(int j=i+1;j&lt;=cnt-i+1;j++){ cout&lt;&lt;i&lt;&lt;&#34; &#34;&lt;&lt;j&lt;&lt;&#34;\n&#34;; if(i==1&amp;&amp;j==cnt-i+1){ int now=j; while(n%3!=0){ cout&lt;&lt;i&lt;&lt;&#34; &#34;&lt;&lt;++now&lt;&lt;&#34;\n&#34;; n--; } } } } } else{ for(int i=2;i&lt;=n+1;i++)cout&lt;&lt;&#34;1 &#34;&lt;&lt;i&lt;&lt;&#34;\n&#34;; } } int main() { int t; cin &gt;&gt; t; while (t--) solve(); return 0; } 传奇勇士小凯 有⼀个 n 个结点的有根树，你需要从 1 号结点走到任意⼀个叶子节点，每天你有 p[i]/15 的可能性可以向任意⼀个儿子节点走⼀步（ i 为你当前所在的节点编号），询问你期望最多可以在这颗树上走多久
期望计算，在某一节点停留的步数应该为 15/p[i] 。
#include &lt;bits/stdc++.h&gt; using namespace std; typedef long long ll; const int N = 1e5+7; ll ans=0, LCM=360360; vector&lt;int&gt; nxt[N]; vector&lt;int&gt; p(N); ll gcd(int x,int y){ if(!x||!y)return x+y; return gcd(y,x%y); } void dfs(int u,int fa, ll sum) { sum += (LCM / p[u]); if(sum&gt;ans)ans=sum; for (auto x : nxt[u]) { if(x==fa)continue; dfs(x, u, sum); } } void solve() { int n; cin &gt;&gt; n; ans=0; for (int i = 1; i &lt; n; i++) { int u, v; cin &gt;&gt; u &gt;&gt; v; nxt[u].push_back(v); nxt[v].push_back(u); } for (int i = 1; i &lt;= n; i++) cin &gt;&gt; p[i]; dfs(1, 0, 0); ll d=gcd(15*ans,LCM); printf(&#34;%lld/%lld\n&#34;,15*ans/d,LCM/d); for (int i = 1; i &lt;= n; i++) nxt[i].clear(); } int main() { int t; cin &gt;&gt; t; while (t--) solve(); return 0; } 绝对不模拟的简单魔方 1)暴力，从初始状态开始模拟，每次对比当前状态和给出状态，若相同或不同点仅两个，即得到答案
2)将魔方视为 2 阶的，预处理得到 24 种可能状态，与给出状态对比，至多有一个角不同，即为答案。
之后补... 在 A 里面找有 C 的 B AC自动机（还不会，之后补&hellip;.

0721学习记录 今天集训休息，自己看了看代码源的视频补知识点
kmp相关 子串查询 输入两个字符串s,p,查询p是否在s中出现,若出现输出出现位置,否则输出-1
简化版
#include &lt;bits/stdc++.h&gt; using namespace std; string s,p; int nxt[100001],f[100001],n,m; void kmp(){ n=s.size(); m=p.size(); int j=0; nxt[0]=0; p=p+&#34;#&#34;+s; for(int i=1;i&lt;m+n+1;i++){ while(j&amp;&amp;p[i]!=p[j]) j=nxt[j-1]; if(p[i]==p[j]) j++; nxt[i]=j; } for(int i=m+1;i&lt;n+m+1;i++){ if(nxt[i]==m)cout&lt;&lt;i-2*m+1&lt;&lt;endl; } } int main(){ cin&gt;&gt;s&gt;&gt;p; kmp(); return 0; } 常规版
#include &lt;bits/stdc++.h&gt; using namespace std; string s,p; int nxt[100001],f[100001],n,m; void kmp(){ n=s.size(); m=p.size(); int j=0; nxt[0]=0; for(int i=1;i&lt;m;i++){ while(j&amp;&amp;p[i]!=p[j]) j=nxt[j-1]; if(p[i]==p[j]) j++; nxt[i]=j; } j=0; for(int i=0;i&lt;n;i++){ while(j==m||(j&amp;&amp;s[i]!=p[j])) j=nxt[j-1]; if(s[i]==p[j]) j++; f[i]=j; } for(int i=0;i&lt;n;i++){ if(f[i]==m)cout&lt;&lt;i&lt;&lt;endl; } } int main(){ cin&gt;&gt;s&gt;&gt;p; kmp(); return 0; } 寻找最小循环子串 字符串s是由某个子串重复连接而成的，寻找构成s的最小子串的长度
答案其实就是n-nxt[n]
#include &lt;bits/stdc++.h&gt; using namespace std; string s,p; int nxt[100001],n,m; void kmp(){y m=p.size(); int j=0; nxt[0]=0; p=p; for(int i=1;i&lt;m;i++){ while(j&amp;&amp;p[i]!=p[j]) j=nxt[j-1]; if(p[i]==p[j]) j++; nxt[i]=j; } cout&lt;&lt;m-nxt[m-1]&lt;&lt;endl; } int main(){ cin&gt;&gt;p; kmp(); return 0; } Secret word 给出字符串s，寻找最长字符串p，p满足（是s的子串，翻转后是s的前缀）
#include &lt;bits/stdc++.h&gt; using namespace std; string s; int nxt[200001],n; void kmp(){ n=s.size(); int j=0; nxt[0]=0; string t=s; reverse(t.begin(),t.end()); s=s+&#34;#&#34;+t; for(int i=1;i&lt;n*2+1;i++){ while(j&amp;&amp;s[i]!=s[j]) j=nxt[j-1]; if(s[i]==s[j]) j++; nxt[i]=j; } int ans=-1; for(int i=n;i&lt;2*n+1;i++){ ans=max(ans,nxt[i]); } for(int i=ans-1;i&gt;=0;i--)cout&lt;&lt;s[i]; } int main(){ cin&gt;&gt;s; kmp(); return 0; } exkmp 洛谷 P5410
#include &lt;bits/stdc++.h&gt; using namespace std; const int N = 2e7+10; typedef long long ll; string s,p; ll z[N*2],n,m; void exkmp(string s,string p){ n=s.size(); m=p.size(); p=p+&#34;#&#34;+s; ll L=0,R=-1; z[0]=m; for(int i=1;i&lt;n+m+1;i++){ if(i&gt;R) z[i]=0; else{ ll k=i-L; z[i]=min(z[k],R-i); } while(i+z[i]&lt;n+m+1&amp;&amp;p[z[i]]==p[i+z[i]]) ++z[i]; if(i+z[i]-1&gt;R) L=i,R=i+z[i]-1; } ll ans=0; for(int i=0;i&lt;m;i++)ans^=(1LL*(i+1)*(z[i]+1)); cout&lt;&lt;ans&lt;&lt;&#34;\n&#34;; ans=0; for(int i=0;i&lt;n;i++)ans^=(1LL*(i+1)*(z[i+m+1]+1)); cout&lt;&lt;ans&lt;&lt;&#34;\n&#34;; } int main(){ cin&gt;&gt;s&gt;&gt;p; exkmp(s,p); return 0; }
